const functions = require('@google-cloud/functions-framework');
const { BigQuery } = require('@google-cloud/bigquery');
const { Storage } = require('@google-cloud/storage');

const bigquery = new BigQuery();

const ALLOWED_DATASETS = new Set([
  'analytics',
  'sales_data',
  'user_metrics',
  'inventory'
]);

const ALLOWED_PROJECTS = new Set([
  process.env.GCP_PROJECT_ID,
  process.env.ALLOWED_PROJECT_ID
]);

const MAX_ROWS_LIMIT = 10000000;
const RESULT_BUCKET = process.env.RESULT_BUCKET;

function sanitizeIdentifier(identifier) {
  if (!identifier || typeof identifier !== 'string') {
    throw new Error('Invalid identifier provided');
  }
  const sanitized = identifier.replace(/[^a-zA-Z0-9_]/g, '');
  if (sanitized.length === 0 || sanitized.length > 128) {
    throw new Error('Identifier is empty or too long after sanitization');
  }
  return sanitized;
}

function validateDatasetName(dataset) {
  const sanitized = sanitizeIdentifier(dataset);
  if (!ALLOWED_DATASETS.has(sanitized)) {
    throw new Error(`Dataset "${sanitized}" is not in the allowed list`);
  }
  return sanitized;
}

function validateProjectId(projectId) {
  if (!projectId) return process.env.GCP_PROJECT_ID;
  if (!ALLOWED_PROJECTS.has(projectId)) {
    throw new Error(`Project "${projectId}" is not in the allowed list`);
  }
  return projectId;
}

function validateAggregationType(type) {
  const allowedTypes = ['sum', 'avg', 'count', 'min', 'max', 'count_distinct'];
  if (!allowedTypes.includes(type)) {
    throw new Error(`Aggregation type "${type}" is not allowed. Use one of: ${allowedTypes.join(', ')}`);
  }
  return type;
}

function validateDateRange(startDate, endDate) {
  const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
  if (startDate && !dateRegex.test(startDate)) {
    throw new Error('Invalid start date format. Use YYYY-MM-DD');
  }
  if (endDate && !dateRegex.test(endDate)) {
    throw new Error('Invalid end date format. Use YYYY-MM-DD');
  }
  if (startDate && endDate) {
    const start = new Date(startDate);
    const end = new Date(endDate);
    if (isNaN(start.getTime()) || isNaN(end.getTime())) {
      throw new Error('Invalid date values');
    }
    if (start > end) {
      throw new Error('Start date must be before end date');
    }
  }
  return { startDate, endDate };
}

function buildParameterizedQuery(params) {
  const {
    dataset,
    table,
    aggregationType,
    aggregationColumn,
    groupByColumns,
    startDate,
    endDate,
    limit
  } = params;

  const safeDataset = validateDatasetName(dataset);
  const safeTable = sanitizeIdentifier(table);
  const safeAggType = validateAggregationType(aggregationType);
  const safeAggColumn = sanitizeIdentifier(aggregationColumn);
  const safeGroupByCols = groupByColumns.map(col => sanitizeIdentifier(col));
  const { startDate: safeStart, endDate: safeEnd } = validateDateRange(startDate, endDate);

  const safeLimit = Math.min(Math.max(parseInt(limit, 10) || 1000, 1), MAX_ROWS_LIMIT);

  let aggExpression;
  if (safeAggType === 'count_distinct') {
    aggExpression = `COUNT(DISTINCT \`${safeAggColumn}\`)`;
  } else {
    aggExpression = `${safeAggType.toUpperCase()}(\`${safeAggColumn}\`)`;
  }

  const groupByClause = safeGroupByCols.map(col => `\`${col}\``).join(', ');

  let query = `SELECT ${groupByClause}, ${aggExpression} AS aggregated_value
    FROM \`${safeDataset}\`.\`${safeTable}\``;

  const queryParams = {};
  const conditions = [];

  if (safeStart) {
    conditions.push('created_at >= @startDate');
    queryParams.startDate = safeStart;
  }
  if (safeEnd) {
    conditions.push('created_at <= @endDate');
    queryParams.endDate = safeEnd;
  }

  if (conditions.length > 0) {
    query += ` WHERE ${conditions.join(' AND ')}`;
  }

  query += ` GROUP BY ${groupByClause}`;
  query += ` ORDER BY aggregated_value DESC`;
  query += ` LIMIT @resultLimit`;
  queryParams.resultLimit = safeLimit;

  return { query, queryParams };
}

async function executeAggregation(params) {
  const projectId = validateProjectId(params.projectId);
  const { query, queryParams } = buildParameterizedQuery(params);

  console.log('Executing parameterized query for aggregation');

  const options = {
    query,
    params: queryParams,
    location: params.location || 'US',
    projectId,
    maximumBytesBilled: params.maxBytesBilled || '10737418240',
    useLegacySql: false,
    jobTimeoutMs: 480000,
  };

  const [job] = await bigquery.createQueryJob(options);
  console.log(`Job ${job.id} started.`);

  const [rows] = await job.getQueryResults({
    maxResults: MAX_ROWS_LIMIT,
    timeoutMs: 480000,
  });

  const [metadata] = await job.getMetadata();
  const stats = {
    totalBytesProcessed: metadata.statistics.totalBytesProcessed,
    totalBytesBilled: metadata.statistics.query.totalBytesBilled,
    cacheHit: metadata.statistics.query.cacheHit,
    totalRows: rows.length,
    jobId: job.id,
  };

  return { rows, stats };
}

async function processInBatches(params) {
  const batchSize = params.batchSize || 500000;
  const allResults = [];
  let offset = 0;
  let hasMore = true;

  while (hasMore) {
    const batchParams = {
      ...params,
      limit: batchSize,
      offset,
    };

    console.log(`Processing batch at offset ${offset} with size ${batchSize}`);
    const { rows, stats } = await executeAggregation(batchParams);

    allResults.push(...rows);
    console.log(`Batch processed: ${rows.length} rows, ${stats.totalBytesProcessed} bytes`);

    if (rows.length < batchSize) {
      hasMore = false;
    } else {
      offset += batchSize;
    }

    if (allResults.length > MAX_ROWS_LIMIT) {
      console.warn(`Result set exceeds maximum limit of ${MAX_ROWS_LIMIT}. Truncating.`);
      hasMore = false;
    }
  }

  return allResults;
}

async function saveResultsToStorage(results, jobId) {
  if (!RESULT_BUCKET) {
    console.log('No result bucket configured, returning results directly');
    return null;
  }

  const storage = new Storage();
  const bucket = storage.bucket(RESULT_BUCKET);
  const sanitizedJobId = sanitizeIdentifier(jobId || `job_${Date.now()}`);
  const fileName = `aggregation-results/${sanitizedJobId}.json`;
  const file = bucket.file(fileName);

  const jsonData = JSON.stringify(results, null, 2);

  await file.save(jsonData, {
    contentType: 'application/json',
    metadata: {
      cacheControl: 'private, max-age=0',
    },
    predefinedAcl: 'private',
  });

  console.log(`Results saved to gs://${RESULT_BUCKET}/${fileName}`);
  return `gs://${RESULT_BUCKET}/${fileName}`;
}

